# Management Client (RabbitMQ Management REST API)

An internal HTTP client that talks to the [RabbitMQ Management plugin's REST API](https://www.rabbitmq.com/management.html) to manage vhosts. It is **not** part of the public `require('rascal')` export — it is consumed internally by the broker init/teardown tasks. It is documented here because it is the only outbound HTTP contract in the library.

Source: [lib/management/Client.js#L1-L56](https://github.com/cliftonc/rascal/blob/master/lib/management/Client.js#L1-L56)

```js
const http = require('http');
const debug = require('debug')('rascal:management:client');
const format = require('util').format;

function Client(agent) {
  const self = this;

  this.assertVhost = function (name, config, next) { ... };
  this.checkVhost  = function (name, config, next) { ... };
  this.deleteVhost = function (name, config, next) { ... };
  this._request    = function (method, url, options, next) { ... };
  function getUrl(name, config) { ... }
}

module.exports = Client;
```

## Constructor

`new Client(agent)` — `agent` is an `http.Agent` (passed through from `ctx.components.agent`, see [assertVhost.js#L10](https://github.com/cliftonc/rascal/blob/master/lib/amqp/tasks/assertVhost.js#L10-L10)). It is forwarded into every `http.request` call so connection pooling/keep-alive is shared.

## URL construction

Source: [Client.js#L51-L53](https://github.com/cliftonc/rascal/blob/master/lib/management/Client.js#L51-L53)

```js
function getUrl(name, config) {
  return format('%s/%s/%s', config.url, 'api/vhosts', name);
}
```

The request URL is `` `${config.url}/api/vhosts/${name}` ``. `config` is the per-connection **management** config object (`connection.management`), built during configuration.

### How `config` (the management connection) is built

Source: [lib/config/configure.js#L108-L136](https://github.com/cliftonc/rascal/blob/master/lib/config/configure.js#L108-L136)

```js
function configureManagementConnection(vhostConfig, vhostName, connection) {
  connection.management = _.isString(connection.management) ? { url: connection.management } : connection.management;
  const attributesFromUrl = parseConnectionUrl(connection.management.url);
  const attributesFromConfig = getConnectionAttributes(connection.management);
  const defaults = { user: connection.user, password: connection.password, hostname: connection.hostname };

  const connectionAttributes = _.defaultsDeep({ options: null }, attributesFromUrl, attributesFromConfig, defaults);
  setConnectionAttributes(connection.management, connectionAttributes);
  setConnectionUrls(connection.management);
}

function setConnectionUrls(connection) {
  const auth = getAuth(connection.user, connection.password);
  const pathname = connection.vhost === '/' ? '' : connection.vhost;
  const query = connection.options;
  connection.url = url.format({ slashes: true, ...connection, auth, pathname, query });
  connection.loggableUrl = connection.url.replace(/:[^:]*@/, ':***@');
}

function getAuth(user, password) {
  return user && password ? `${user}:${password}` : undefined;
}
```

Key fields on the management `config` consumed by `Client`:
- **`config.url`** — the base URL of the RabbitMQ Management API (e.g. `http://user:pass@host:15672`). The user/password are embedded in the URL's auth component (HTTP Basic auth, via Node's `http.request` parsing of the URL credentials).
- **`config.loggableUrl`** — the same URL with the password masked (`:***@`); used only in error messages so credentials are never logged ([configure.js#L131](https://github.com/cliftonc/rascal/blob/master/lib/config/configure.js#L131-L131)).
- **`config.options`** — extra `http.request` options spread into each request (`{ ...options, method, agent }`).

**Authentication:** HTTP Basic, carried inside `config.url` as `user:password@`. Derived from the management connection's own user/password, falling back to the AMQP connection's `user`/`password`/`hostname` ([configure.js#L112](https://github.com/cliftonc/rascal/blob/master/lib/config/configure.js#L112-L112)).

## Methods

### assertVhost(name, config, next) [MUST] <!-- id: export:lib/management/Client.js:assertVhost -->

Source: [Client.js#L8-L16](https://github.com/cliftonc/rascal/blob/master/lib/management/Client.js#L8-L16)

```js
this.assertVhost = function (name, config, next) {
  debug('Asserting vhost: %s', name);
  const url = getUrl(name, config);
  self._request('PUT', url, config.options, (err) => {
    if (!err) return next();
    const _err = err.status ? new Error(format('Failed to assert vhost: %s. %s returned status %d', name, config.loggableUrl, err.status)) : err;
    return next(_err);
  });
};
```

- **HTTP:** `PUT {config.url}/api/vhosts/{name}` — idempotently creates the vhost (RabbitMQ semantics).
- **Success:** calls `next()` with no error.
- **Failure:** if the error has a `status` (HTTP >= 300), wraps it as `Error('Failed to assert vhost: {name}. {loggableUrl} returned status {status}')`; otherwise (transport error) passes the raw error through.

### checkVhost(name, config, next) [MUST] <!-- id: export:lib/management/Client.js:checkVhost -->

Source: [Client.js#L18-L26](https://github.com/cliftonc/rascal/blob/master/lib/management/Client.js#L18-L26)

```js
this.checkVhost = function (name, config, next) {
  debug('Checking vhost: %s', name);
  const url = getUrl(name, config);
  self._request('GET', url, config.options, (err) => {
    if (!err) return next();
    const _err = err.status ? new Error(format('Failed to check vhost: %s. %s returned status %d', name, config.loggableUrl, err.status)) : err;
    return next(_err);
  });
};
```

- **HTTP:** `GET {config.url}/api/vhosts/{name}` — verifies the vhost exists.
- **Success:** `next()`. **Failure:** same wrapping pattern as `assertVhost` ("Failed to check vhost: ...").

### deleteVhost(name, config, next) [MUST] <!-- id: export:lib/management/Client.js:deleteVhost -->

Source: [Client.js#L28-L36](https://github.com/cliftonc/rascal/blob/master/lib/management/Client.js#L28-L36)

```js
this.deleteVhost = function (name, config, next) {
  debug('Deleting vhost: %s', name);
  const url = getUrl(name, config);
  self._request('DELETE', url, config.options, (err) => {
    if (!err) return next();
    const _err = err.status ? new Error(format('Failed to delete vhost: %s. %s returned status %d', name, config.loggableUrl, err.status)) : err;
    return next(_err);
  });
};
```

- **HTTP:** `DELETE {config.url}/api/vhosts/{name}` — removes the vhost.
- **Success:** `next()`. **Failure:** same wrapping pattern ("Failed to delete vhost: ...").

### _request(method, url, options, next) [SHOULD] <!-- id: export:lib/management/Client.js:_request -->

Internal HTTP transport shared by all three public methods.

Source: [Client.js#L38-L49](https://github.com/cliftonc/rascal/blob/master/lib/management/Client.js#L38-L49)

```js
this._request = function (method, url, options, next) {
  const req = http.request(url, { ...options, method, agent }, (res) => {
    if (res.statusCode >= 300) {
      const err = Object.assign(new Error('HTTP Error'), { status: res.statusCode });
      return next(err);
    }
    res.on('data', () => {});
    res.on('end', () => next());
  });
  req.on('error', next);
  req.end();
};
```

Contract / semantics:
- Issues `http.request(url, { ...config.options, method, agent })` with an empty body (`req.end()` with no payload).
- **HTTP status >= 300 = failure:** any response status code of 300 or greater produces an `Error('HTTP Error')` decorated with `.status = res.statusCode`. This `.status` is what the wrapping methods test for to build their descriptive error messages.
- Status codes < 300 are treated as success: the response body is drained (`res.on('data', () => {})`) and `next()` is called with no error on `end`.
- Transport-level errors (`req.on('error', next)`) propagate the raw error (no `.status`), so callers pass them through unchanged.

## Retry / URL-cycling (caller side)

The `Client` itself performs no retries. URL-cycling across multiple connection candidates is handled by the broker tasks that invoke it.

Source: [lib/amqp/tasks/assertVhost.js#L6-L29](https://github.com/cliftonc/rascal/blob/master/lib/amqp/tasks/assertVhost.js#L6-L29) (the `checkVhost` and `deleteVhost` tasks follow the same pattern)

```js
module.exports = _.curry((config, ctx, next) => {
  if (!config.assert) return next(null, config, ctx);

  const candidates = config.connections;
  const client = new Client(ctx.components.agent);

  async.retry(
    candidates.length,
    (cb) => {
      const connectionConfig = candidates[ctx.connectionIndex];
      client.assertVhost(config.name, connectionConfig.management, (err) => {
        if (err) {
          ctx.connectionIndex = (ctx.connectionIndex + 1) % candidates.length;
          return cb(err);
        }
        ctx.connectionConfig = connectionConfig;
        cb();
      });
    },
    (err) => { next(err, config, ctx); },
  );
});
```

- Uses `async.retry` with the retry count equal to the number of connection `candidates`.
- On each attempt it picks `candidates[ctx.connectionIndex].management` as the `config` for the client.
- On failure it advances `ctx.connectionIndex` round-robin (`(index + 1) % candidates.length`) and retries against the next connection's management endpoint.
- On success it records the working `connectionConfig` on `ctx`.
- Gated by `config.assert` (assertVhost task) — skipped entirely when assertion is disabled.

# Public Exports

The package entry point. The object returned by `require('rascal')` is the complete public API contract.

Source: [index.js#L1-L24](https://github.com/cliftonc/rascal/blob/master/index.js#L1-L24)

```js
const _ = require('lodash');
const defaultConfig = require('./lib/config/defaults');
const testConfig = require('./lib/config/tests');
const Broker = require('./lib/amqp/Broker');
const BrokerAsPromised = require('./lib/amqp/BrokerAsPromised');
const counters = require('./lib/counters');

module.exports = (function () {
  return {
    Broker,
    BrokerAsPromised,
    createBroker: Broker.create,
    createBrokerAsPromised: BrokerAsPromised.create,
    defaultConfig,
    testConfig,
    withDefaultConfig(config) {
      return _.defaultsDeep({}, config, defaultConfig);
    },
    withTestConfig(config) {
      return _.defaultsDeep({}, config, testConfig);
    },
    counters,
  };
}());
```

The module export is an IIFE returning a static object literal. There are nine top-level keys, all enumerated below. Every key is part of the API contract and tagged `[MUST]`.

---

### Broker [MUST] <!-- id: file:index.js:index.js -->

The callback-style broker class, re-exported as-is from `./lib/amqp/Broker`.

Source: [index.js#L4](https://github.com/cliftonc/rascal/blob/master/index.js#L4-L4), [index.js#L10](https://github.com/cliftonc/rascal/blob/master/index.js#L10-L10)

- Exposed as the constructor/namespace `Broker`.
- Carries the static factory `Broker.create` (see `createBroker`).
- Instances inherit from `EventEmitter` ([Broker.js#L36](https://github.com/cliftonc/rascal/blob/master/lib/amqp/Broker.js#L36-L36)).
- Consumers normally construct a broker via the `createBroker` factory rather than `new Broker(...)` directly; the constructor expects an already-augmented (preflighted) config.

---

### BrokerAsPromised [MUST] <!-- id: export:index.js:BrokerAsPromised -->

The promise-style broker class, re-exported as-is from `./lib/amqp/BrokerAsPromised`.

Source: [index.js#L5](https://github.com/cliftonc/rascal/blob/master/index.js#L5-L5), [index.js#L11](https://github.com/cliftonc/rascal/blob/master/index.js#L11-L11)

- Wraps a callback `Broker`, converting its methods to promises ([BrokerAsPromised.js#L32-L40](https://github.com/cliftonc/rascal/blob/master/lib/amqp/BrokerAsPromised.js#L32-L40)).
- Promisified methods: `connect`, `nuke`, `purge`, `shutdown`, `bounce`, `publish`, `forward`, `unsubscribeAll` ([BrokerAsPromised.js#L33](https://github.com/cliftonc/rascal/blob/master/lib/amqp/BrokerAsPromised.js#L33-L33)).
- Inherits from `EventEmitter` and forwards events from the underlying broker via `forward-emitter` ([BrokerAsPromised.js#L30,L36](https://github.com/cliftonc/rascal/blob/master/lib/amqp/BrokerAsPromised.js#L30-L36)).
- Carries the static factory `BrokerAsPromised.create` (see `createBrokerAsPromised`).

---

### createBroker(config, [components], callback) [MUST] <!-- id: export:index.js:createBroker -->

Callback factory. Alias of `Broker.create`.

Source: [index.js#L12](https://github.com/cliftonc/rascal/blob/master/index.js#L12-L12) → [Broker.js#L20-L33](https://github.com/cliftonc/rascal/blob/master/lib/amqp/Broker.js#L20-L33)

```js
create: function create(config, components, next) {
  if (arguments.length === 2) return create(config, {}, arguments[1]);

  const counters = _.defaults({}, components.counters, {
    stub,
    inMemory,
    inMemoryCluster,
  });

  preflight(_.cloneDeep(config), (err, augmentedConfig) => {
    if (err) return next(err);
    new Broker(augmentedConfig, _.assign({}, components, { counters }))._init(next);
  });
},
```

Signature / contract:
- `config` (object, required) — the Rascal broker configuration.
- `components` (object, optional) — overridable dependencies, e.g. `counters`. When called with exactly **2 arguments**, the second argument is treated as the callback and `components` defaults to `{}`.
- `callback` / `next` (function, required) — node-style `(err, broker)`.
- Default `components.counters` is `{ stub, inMemory, inMemoryCluster }` (the worker variant of `inMemoryCluster`).
- The config is deep-cloned and passed through `preflight` (validation/configuration) before the `Broker` is constructed and `_init`-ialised.

---

### createBrokerAsPromised(config, [components]) [MUST] <!-- id: export:index.js:createBrokerAsPromised -->

Promise factory. Alias of `BrokerAsPromised.create`.

Source: [index.js#L13](https://github.com/cliftonc/rascal/blob/master/index.js#L13-L13) → [BrokerAsPromised.js#L9-L27](https://github.com/cliftonc/rascal/blob/master/lib/amqp/BrokerAsPromised.js#L9-L27)

```js
create() {
  const args = Array.prototype.slice.call(arguments);
  return new Promise((resolve, reject) => {
    Broker.create(
      ...args.concat((err, broker) => {
        if (err && !broker) return reject(err);
        broker.promises = true;
        const brokerAsPromised = new BrokerAsPromised(broker);
        if (!err) return resolve(brokerAsPromised);
        err.broker = Symbol('broker-as-promised');
        Object.defineProperty(err, err.broker, {
          enumerable: false,
          value: brokerAsPromised,
        });
        return reject(err);
      }),
    );
  });
},
```

Signature / contract:
- Same positional arguments as `createBroker` minus the callback: `(config)` or `(config, components)`.
- Returns a `Promise<BrokerAsPromised>`.
- Resolves with a `BrokerAsPromised` instance on success.
- On error **with** a broker available, rejects with the error and attaches the `BrokerAsPromised` instance to the error under a non-enumerable `Symbol` key stored at `err.broker` (so callers can still shut the partially-built broker down).
- On error **without** a broker, rejects with the raw error.

---

### defaultConfig [MUST] <!-- id: export:index.js:defaultConfig -->

The default Rascal configuration object, re-exported from `./lib/config/defaults`.

Source: [index.js#L2](https://github.com/cliftonc/rascal/blob/master/index.js#L2-L2), [index.js#L14](https://github.com/cliftonc/rascal/blob/master/index.js#L14-L14) → `lib/config/defaults.js`

- A plain configuration object containing sane default vhost/connection/publication/subscription settings, merged into user config by `withDefaultConfig`.

---

### testConfig [MUST] <!-- id: export:index.js:testConfig -->

The test configuration object, re-exported from `./lib/config/tests`.

Source: [index.js#L3](https://github.com/cliftonc/rascal/blob/master/index.js#L3-L3), [index.js#L15](https://github.com/cliftonc/rascal/blob/master/index.js#L15-L15) → `lib/config/tests.js`

- A configuration object tuned for tests (e.g. namespacing, auto-delete), merged into user config by `withTestConfig`.

---

### withDefaultConfig(config) [MUST] <!-- id: export:index.js:withDefaultConfig -->

Merges the supplied `config` over `defaultConfig` and returns a new object.

Source: [index.js#L16-L18](https://github.com/cliftonc/rascal/blob/master/index.js#L16-L18)

```js
withDefaultConfig(config) {
  return _.defaultsDeep({}, config, defaultConfig);
},
```

Contract:
- Returns `_.defaultsDeep({}, config, defaultConfig)` — a fresh object where `config` values take precedence and `defaultConfig` fills in any missing keys (deep merge).
- Pure: does not mutate `config` or `defaultConfig` (writes into a new `{}`).

---

### withTestConfig(config) [MUST] <!-- id: export:index.js:withTestConfig -->

Merges the supplied `config` over `testConfig` and returns a new object.

Source: [index.js#L19-L21](https://github.com/cliftonc/rascal/blob/master/index.js#L19-L21)

```js
withTestConfig(config) {
  return _.defaultsDeep({}, config, testConfig);
},
```

Contract:
- Returns `_.defaultsDeep({}, config, testConfig)` — a fresh object where `config` values take precedence and `testConfig` fills in missing keys (deep merge).
- Pure: does not mutate inputs.

---

### counters [MUST] <!-- id: export:index.js:counters -->

The counter implementations object, re-exported from `./lib/counters`.

Source: [index.js#L6](https://github.com/cliftonc/rascal/blob/master/index.js#L6-L6), [index.js#L22](https://github.com/cliftonc/rascal/blob/master/index.js#L22-L22) → [lib/counters/index.js#L1-L9](https://github.com/cliftonc/rascal/blob/master/lib/counters/index.js#L1-L9)

```js
const stub = require('./stub');
const inMemory = require('./inMemory');
const inMemoryCluster = require('./inMemoryCluster');

module.exports = {
  stub,
  inMemory,
  inMemoryCluster,
};
```

Contract — exposes three counter strategies (used for redelivery/retry counting):
- `counters.stub` — no-op counter.
- `counters.inMemory` — single-process in-memory counter.
- `counters.inMemoryCluster` — cluster-aware in-memory counter (master/worker variants; `Broker.create` uses the `.worker` form as its default).

These can be supplied to `createBroker`/`createBrokerAsPromised` via `components.counters` to override the defaults.

# Value Objects

This layer has no embeddable classes. The "value objects" of the domain are
(1) the **fully-qualified name** (FQN) — a computed string identity derived from
a base name + namespace prefix + uniqueness suffix — and (2) the **default
config presets** that layer on top of `baseline.js` to produce the final entity
shapes.

## Fully-Qualified Naming

### fqn.js [MUST] <!-- id: file:lib/config/fqn.js:fqn.js -->

[fqn.js](https://github.com/cliftonc/rascal/blob/master/lib/config/fqn.js#L1-L20)

Computes the `fullyQualifiedName` for exchanges and queues (and FQN-qualified
binding keys / dead-letter-exchange args). The FQN is the actual AMQP resource
name; the short `name` is the config alias.

```javascript
function qualify(name, namespace, unique) {
  if (name === '') return name;            // nameless default exchange stays ''
  name = prefix(namespace, name);          // namespace:name
  name = suffix(unique || undefined, name);// name:unique
  return name;
}

function prefix(text, name, separator) {
  return text ? text + (separator || ':') + name : name;
}

function suffix(text, name, separator) {
  return text ? name + (separator || ':') + text : name;
}
```

Rules:
- Default separator is `:`.
- Empty `name` (`''`, the default nameless exchange) is returned unqualified.
- `namespace` falsy → no prefix; `unique` falsy → no suffix.
- Result form: `[namespace:]name[:unique]`. Example: namespace `app`, name
  `orders`, unique `abc` → `app:orders:abc`.
- `unique` is used for reply queues (the `replyTo` UUID) so each subscriber gets
  a distinct queue.

## Default Config Presets

The final config is built by deep-merging three layers, lowest priority last:
explicit user config → preset (`tests.js` or `defaults.js`) → `baseline.js`.

### defaults.js [MUST] <!-- id: file:lib/config/defaults.js:defaults.js -->

[defaults.js](https://github.com/cliftonc/rascal/blob/master/lib/config/defaults.js#L1-L21)

The **production** default preset. Sole exported object, deep-merged onto user
config (above `baseline.js`).

```javascript
module.exports = {
  defaults: {
    vhosts: {
      connection: {
        options: { heartbeat: 10, connection_timeout: 10000, channelMax: 100 },
        socketOptions: { timeout: 10000 },
        management: { options: { timeout: 1000 } },
      },
    },
  },
};
```

Adds connection-level defaults that `baseline.js` leaves empty: AMQP heartbeat
(10s), connection timeout (10s), channel max (100), socket timeout (10s),
management API timeout (1s).

### tests.js [SHOULD] <!-- id: file:lib/config/tests.js:tests.js -->

[tests.js](https://github.com/cliftonc/rascal/blob/master/lib/config/tests.js#L1-L44)

The **test** default preset. Deep-merges its own overrides *onto* `defaults.js`
(`_.defaultsDeep(testOverrides, defaultConfig)`), so it is a superset of the
production defaults tuned for fast, ephemeral test topologies. Tagged [SHOULD]
because it is a test-only convenience, not part of the production contract.

```javascript
const _ = require('lodash').runInContext();
const defaultConfig = require('./defaults');

module.exports = _.defaultsDeep(
  {
    defaults: {
      vhosts: {
        connection: { options: { heartbeat: 50 } },  // overrides defaults.js heartbeat: 10
        namespace: true,                              // unique vhost namespace per run (UUID)
        exchanges: { options: { durable: false } },   // ephemeral exchanges
        queues: { purge: true, options: { durable: false } }, // ephemeral, auto-purged queues
      },
      publications: { options: { persistent: false } },  // non-persistent messages
      subscriptions: { closeTimeout: 500 },
    },
    redeliveries: { counters: { inMemory: { size: 1000 } } },
  },
  defaultConfig,
);
```

Key test-only behaviors:
- `namespace: true` → every vhost gets a random-UUID namespace, isolating
  parallel test runs (resolved to a UUID in [configure.js:54](https://github.com/cliftonc/rascal/blob/master/lib/config/configure.js#L54)).
- `durable: false` on exchanges/queues and `persistent: false` on publications →
  nothing survives broker restart.
- `queues.purge: true` → queues are purged on startup.
- `heartbeat: 50` overrides the production `heartbeat: 10`.

# Broker

The orchestrator. Holds the registries of vhosts, publications, subscriptions, and active subscriber sessions; exposes the public API (`publish`, `forward`, `subscribe`, lifecycle commands) and composes the init task chain.

## Broker.js [MUST] <!-- id: file:lib/amqp/Broker.js:Broker.js -->

[Broker.js](https://github.com/cliftonc/rascal/blob/master/lib/amqp/Broker.js#L1-L232) · `inherits(Broker, EventEmitter)`

### Factory: `Broker.create(config, [components], next)` [MUST]

Callback factory. Runs the preflight pipeline then constructs and initialises the broker.

```js
const preflight = async.compose(validate, configure); // configure THEN validate
create: function create(config, components, next) {
  if (arguments.length === 2) return create(config, {}, arguments[1]); // components optional
  const counters = _.defaults({}, components.counters, { stub, inMemory, inMemoryCluster });
  preflight(_.cloneDeep(config), (err, augmentedConfig) => {
    if (err) return next(err);
    new Broker(augmentedConfig, _.assign({}, components, { counters }))._init(next);
  });
}
```

- `preflight = async.compose(validate, configure)` — runs `configure` first, then `validate` (async.compose is right-to-left).
- Default counter components injected: `stub`, `inMemory` (`../counters/inMemory`), `inMemoryCluster` (`../counters/inMemoryCluster`.worker). User-supplied `components.counters` win via `_.defaults`.
- Config is deep-cloned before preflight.

### Init task chain [MUST]

```js
const init = async.compose(tasks.initShovels, tasks.initSubscriptions, tasks.initPublications, tasks.initCounters, tasks.initVhosts);
```

**Execution order (async.compose is right-to-left):** `initVhosts` → `initCounters` → `initPublications` → `initSubscriptions` → `initShovels`.

`_init` resets all registries, runs `init(config, { broker: self, components }, …)`, then sets a `keepActive` interval (`setInterval(_.noop, maxInterval)`, `maxInterval = 2147483647`) to keep the event loop alive, and yields `next(err, self)` via `setImmediate`.

### Lifecycle command chains [MUST]

Composed in the constructor:

```js
const nukeVhost = async.compose(tasks.deleteVhost, tasks.shutdownVhost, tasks.nukeVhost); // order: nukeVhost → shutdownVhost → deleteVhost
const purgeVhost = tasks.purgeVhost;
const forewarnVhost = tasks.forewarnVhost;
const shutdownVhost = tasks.shutdownVhost;
const bounceVhost = tasks.bounceVhost;
```

- **`shutdown(next)`** — for each vhost: `forewarnVhost`; then `unsubscribeAll`; then for each vhost: `shutdownVhost`; then `clearInterval(keepActive)`. Uses `async.eachSeries`.
- **`bounce(next)`** — `unsubscribeAll`, then `bounceVhost` per vhost (`async.eachSeries`).
- **`nuke(next)`** — `unsubscribeAll`, then `nukeVhost` per vhost; on success clears `vhosts`/`publications`/`subscriptions` registries and `clearInterval(keepActive)`.
- **`purge(next)`** — `purgeVhost` per vhost (`async.eachSeries`).

### Connection / registry methods [MUST]

```js
this.connect = (name, next) => { if (!vhosts[name]) return next(Error('Unknown vhost')); vhosts[name].connect(next); };
this.getConnections = () => Object.keys(vhosts).map(n => vhosts[n].getConnectionDetails());
this.getFullyQualifiedName = this.qualify = (vhost, name) => fqn.qualify(name, config.vhosts[vhost].namespace);
this._addVhost / _addPublication / _addSubscription   // registry mutators called by tasks
```

### Publish / forward [MUST]

```js
this.publish = (name, message, overrides, next) => {
  if (arguments.length === 3) return self.publish(name, message, {}, arguments[2]);   // overrides optional
  if (_.isString(overrides)) return self.publish(name, message, { routingKey: overrides }, next); // string => routingKey
  if (!publications[name]) return next(Error('Unknown publication'));
  publications[name].publish(message, overrides, next);
};
this.forward = (name, message, overrides, next) => { /* same arg-shuffling; checks config.publications[name]; publications[name].forward(...) */ };
```

`next` receives `(err, publicationSession)`.

### Subscribe / subscribeAll / unsubscribeAll [MUST]

```js
this.subscribe = (name, overrides, next) => {
  if (arguments.length === 2) return self.subscribe(name, {}, arguments[1]);
  if (!subscriptions[name]) return next(Error('Unknown subscription'));
  subscriptions[name].subscribe(overrides, (err, session) => {
    if (err) return next(err);
    sessions.push(session);   // track for unsubscribeAll
    next(null, session);
  });
};
this.subscribeAll = (filter, next) => { /* filter optional (default () => true); subscribes config.subscriptions matching filter via async.mapSeries */ };
this.unsubscribeAll = (next) => { async.each(sessions.slice(), (session, cb) => { sessions.shift(); session.cancel(cb); }, next); };
```

### Events

`Broker` extends `EventEmitter`. It re-emits all vhost events (see [vhost.md](vhost.md)) because `initVhosts` calls `forwardEvents(vhost, broker)`. It emits `error` directly when `unsubscribeAll` fails inside `shutdown`/`bounce`/`nuke`, and (via shovels) `error`/`cancelled`.

