### inMemoryCluster.js [MUST] <!-- id: file:lib/counters/inMemoryCluster.js:inMemoryCluster.js -->

[lib/counters/inMemoryCluster.js#L1-L71](https://github.com/cliftonc/rascal/blob/master/lib/counters/inMemoryCluster.js#L1-L71)

Cluster-aware counter. The **master** process holds the single authoritative
`inMemory` counter; **worker** processes proxy `incrementAndGet` to the master
over node `cluster` IPC, correlating requests/responses by UUID via `stashback`.
`Broker` uses `.worker` ([Broker.js:15](https://github.com/cliftonc/rascal/blob/master/lib/amqp/Broker.js#L15)); the host app must call `.master(options)` in the primary process.

```js
const cluster = require('cluster');
const uuid = require('uuid').v4;
const Stashback = require('stashback');
const inMemory = require('./inMemory');

const debug = 'rascal:counters:inMemoryCluster';

module.exports = {
  master: function master(options) {
    const workers = {};
    const counter = inMemory(options);

    function handleMessage(worker, message) {
      if (message.sender !== 'rascal-in-memory-cluster-counter' || message.cmd !== 'incrementAndGet') return;
      counter.incrementAndGet(message.key, (err, value) => {
        worker.send({
          sender: 'rascal-in-memory-cluster-counter',
          correlationId: message.correlationId,
          value: err ? 1 : value,
        });
      });
    }

    cluster
      .on('fork', (worker) => {
        workers[worker.id] = worker;
        worker.on('message', (message) => {
          handleMessage(worker, message);
        });
      })
      .on('disconnect', (worker) => {
        delete workers[worker.id];
      })
      .on('exit', (worker) => {
        delete workers[worker.id];
      });
  },
  worker: function worker(options) {
    if (!cluster.isWorker) throw new Error("You cannot use Rascal's in memory cluster counter outside of a cluster");
    if (!options) return worker({});
    const timeout = options.timeout || 100;
    const stashback = Stashback({ timeout });

    process.on('message', (message) => {
      if (message.sender !== 'rascal-in-memory-cluster-counter') return;
      stashback.unstash(message.correlationId, (err, cb) => {
        err ? cb(null, 1) : cb(null, message.value);
      });
    });

    return {
      incrementAndGet(key, cb) {
        const correlationId = uuid();
        stashback.stash(
          correlationId,
          (err, value) => {
            err ? cb(null, 1) : cb(null, value);
          },
          (err) => {
            if (err) return cb(null, 1);
            process.send({
              sender: 'rascal-in-memory-cluster-counter',
              correlationId,
              cmd: 'incrementAndGet',
            });
          },
        );
      },
    };
  },
};
```

**IPC protocol constants [MUST]:**

| Constant | Value | Purpose |
|----------|-------|---------|
| message `sender` | `'rascal-in-memory-cluster-counter'` | namespaces messages; non-matching messages ignored |
| `cmd` | `'incrementAndGet'` | only command supported |
| `correlationId` | `uuid.v4()` | matches worker request to master response |
| `options.timeout` (worker) | 100 (ms) | stashback timeout before falling back to `1` |

**master(options) [MUST]:**
- Creates one shared `inMemory(options)` counter (same `size` default of 1000).
- Tracks live workers in `workers` map (`fork` adds; `disconnect`/`exit` delete).
- On a matching `incrementAndGet` message, increments the shared counter and replies to the originating worker with `{ correlationId, value }` (`value = 1` if the master counter errored).

**worker(options) [MUST]:**
- Throws `"You cannot use Rascal's in memory cluster counter outside of a cluster"` if `!cluster.isWorker`.
- Normalises missing `options` by recursing with `{}`.
- Listens for master replies; `unstash`es the pending callback by `correlationId`.
- `incrementAndGet(key, cb)`: stashes `cb` under a new `correlationId`, then sends the increment request to the master. The `key` travels in the original code path via `message.key` — note the worker's `process.send` does **not** include `key` (see Unknowns).

**Failure fallbacks [MUST]:**

| Failure point | Fallback value |
|---------------|----------------|
| master counter error | `1` (sent as `value`) |
| stashback stash setup error | `cb(null, 1)` |
| stashback timeout / unstash error | `cb(null, 1)` |

## Unknowns

- In `worker.incrementAndGet`, the outbound `process.send(...)` payload
  (inMemoryCluster.js:61-66) does **not** include the `key` field, yet
  `master.handleMessage` reads `message.key` (line 15). As written, the master
  receives `undefined` as the key, so all worker-originated counts share a single
  bucket. This is the verifiable behavior of the current source; intent is not
  documented in code.

# Harness & Strategy

## Runner

Tests run under [zUnit](https://www.npmjs.com/package/zunit) v4. Configuration lives in `package.json`:

[package.json](https://github.com/cliftonc/rascal/blob/master/package.json#L37-L68)

```json
"scripts": {
  "test": "zUnit",
  "coverage": "nyc --report html --reporter lcov --reporter text-summary zUnit",
  "docker": "docker run -d --name rascal-rabbitmq -p 5672:5672 -p 15672:15672 rabbitmq:3.12.9-management-alpine"
},
"zUnit": {
  "pollute": true,
  "pattern": "^[\\w-]+.tests.js$"
}
```

- `pattern` `^[\w-]+.tests.js$` selects test files (matches `broker.tests.js` etc., recursively under `test/`).
- `pollute: true` makes zUnit inject `describe` / `it` as globals (no per-file `require` of the runner).
- zUnit's `it` callback signature is `(test, done)` for async tests, or a function returning a Promise. Synchronous tests use a no-arg function. Per-test and per-suite options are passed as a trailing object, e.g. `it('name', fn, { timeout: 60000 })` and `}, { timeout: 6000 })` on the `describe`.

## Broker dependency

Most suites are integration tests against a live RabbitMQ. The expected broker:

- Image `rabbitmq:3.12.9-management-alpine` (management plugin required).
- AMQP on `localhost:5672`, management HTTP API on `localhost:15672`.
- Default credentials `guest:guest`.

The management API is used directly by tests and helpers to assert/check/delete vhosts and to forcibly kill connections (simulating broker-side disconnects for recovery tests).

Pure unit suites that need NO broker: `test/backoff/*`, `test/caches/inMemory.tests.js`, `test/config.tests.js`, `test/defaults.tests.js`, `test/validation.tests.js`.

## Shared test config

Integration suites merge their per-test config over a shared base via `lodash` `defaultsDeep`:

[lib/config/tests.js](https://github.com/cliftonc/rascal/blob/master/lib/config/tests.js)

```js
const _ = require('lodash').runInContext();
const defaultConfig = require('./defaults');

module.exports = _.defaultsDeep({
  defaults: {
    vhosts: {
      connection: { options: { heartbeat: 50 } },
      namespace: true,
      exchanges: { options: { durable: false } },
      queues: { purge: true, options: { durable: false } },
    },
    publications: { options: { persistent: false } },
    subscriptions: { closeTimeout: 500 },
  },
  redeliveries: { counters: { inMemory: { size: 1000 } } },
}, defaultConfig);
```

This base makes test topology ephemeral: non-durable exchanges/queues, purge-on-create, short heartbeat, and `namespace: true` so each suite/test namespaces its objects with a per-test `uuid()` to avoid cross-test collisions.

## Common per-suite pattern (integration suites)

```js
const Broker = require('..').Broker;            // or BrokerAsPromised
const AmqpUtils = require('./utils/amqputils');
const testConfig = require('../lib/config/tests');

describe('Suite', () => {
  let broker, amqputils, namespace, vhosts;

  beforeEach((test, done) => {
    namespace = uuid();                         // unique namespace per test
    vhosts = { '/': { namespace, exchanges: {...}, queues: {...}, bindings: {...} } };
    amqplib.connect((err, connection) => {      // raw amqplib connection for assertions
      amqputils = AmqpUtils.init(connection);
      done();
    });
  });

  afterEach((test, done) => {
    amqputils.disconnect(() => {
      if (broker) return broker.nuke(done);     // tear down topology + connections
      done();
    });
  });

  function createBroker(config, next) {
    config = _.defaultsDeep(config, testConfig);
    Broker.create(config, (err, _broker) => { broker = _broker; next(err, broker); });
  }
}, { timeout: 2000 });                          // suite-level timeout
```

Key conventions:
- Each suite owns a private `createBroker` that deep-merges the per-test config over `testConfig` and captures the broker for `afterEach` teardown (`broker.nuke`).
- A separate raw `amqplib` connection (wrapped by `amqputils`) is used to introspect the broker independently of rascal, asserting messages actually landed / exchanges & queues exist.
- Callback suites use the `(test, done)` signature; `*AsPromised` suites either return a Promise or, for event-driven assertions, fall back to `(test, done)`.

## Dual callback + promise APIs

Every behavioral area is tested twice: a callback suite (`broker.tests.js`, `publications.tests.js`, `subscriptions.tests.js`) and an `AsPromised` mirror (`brokerAsPromised.tests.js`, etc.) that exercises the same behavior through `BrokerAsPromised` and `.then()/.catch()`. The promise suites assert constructor names `SubscriberSessionAsPromised` vs the callback `SubscriberSession`.
